+export function groupBy<T, K extends string>(items: T[], keyFn: (t: T) => K): Record<K, T[]> {
+  const out = {} as Record<K, T[]>;
+  for (const it of items) { const k = keyFn(it); (out[k] ||= []).push(it); }
+  return out;
+}
